type Primitive = string | number | boolean | null;

function describe(value: Primitive): string {
  if (value === null) {
    return "nothing here";
  }
  if (typeof value === "boolean") {
    return `flag: ${value}`;
  }
  if (typeof value === "number") {
    return `number: ${value}`;
  }
  return `text: ${value}`;
}

console.log(describe(null));    // "nothing here"
console.log(describe(true));    // "flag: true"
console.log(describe(42));      // "number: 42"
console.log(describe("hello")); // "text: hello"
